"use strict";(globalThis.webpackChunktemp_docs=globalThis.webpackChunktemp_docs||[]).push([[837],{5660(e){e.exports=JSON.parse('{"archive":{"blogPosts":[{"id":"/2026/03/20/project-launch","metadata":{"permalink":"/documentation/blog/2026/03/20/project-launch","editUrl":"https://github.com/LocalhostLegends/documentation/edit/main/blog/2026-03-20-project-launch/index.md","source":"@site/blog/2026-03-20-project-launch/index.md","title":"HR Platform: Project Launch","description":"We\'re thrilled to announce the official launch of the HR Platform development project! \ud83c\udf89","date":"2026-03-20T00:00:00.000Z","tags":[{"inline":true,"label":"announcement","permalink":"/documentation/blog/tags/announcement"},{"inline":true,"label":"launch","permalink":"/documentation/blog/tags/launch"},{"inline":true,"label":"hr-tech","permalink":"/documentation/blog/tags/hr-tech"}],"readingTime":1.12,"hasTruncateMarker":true,"authors":[{"name":"Development Team","title":"HR Platform Team","url":"https://github.com/LocalhostLegends","imageURL":"https://github.com/LocalhostLegends.png","key":"dev-team","page":null}],"frontMatter":{"title":"HR Platform: Project Launch","authors":["dev-team"],"tags":["announcement","launch","hr-tech"]},"unlisted":false},"content":"We\'re thrilled to announce the official launch of the **HR Platform** development project! \ud83c\udf89\\r\\n\\r\\nToday marks the beginning of our journey to build a modern HR Tech solution for workforce management.\\r\\n\\r\\n\x3c!-- truncate --\x3e\\r\\n\\r\\n## What is HR Platform?\\r\\n\\r\\nHR Platform is a comprehensive web portal designed to automate and streamline HR processes for medium and large companies. Our goal is to create a solution that bridges the gap between HR departments and employees, making workforce management efficient and transparent.\\r\\n\\r\\n## Project Scope\\r\\n\\r\\nThe platform will include:\\r\\n\\r\\n### Core Modules\\r\\n- **\ud83d\udc65 Employee Management** - Complete employee lifecycle management\\r\\n- **\ud83d\udcdd Recruitment** - Streamlined hiring process\\r\\n- **\ud83d\udcca Analytics** - Real-time dashboards and reports\\r\\n- **\ud83d\udd10 Authentication** - Secure role-based access control\\r\\n\\r\\n### Technical Stack\\r\\n- **Backend**: NestJS with TypeScript\\r\\n- **Database**: PostgreSQL with TypeORM\\r\\n- **Authentication**: JWT + Argon2\\r\\n- **Documentation**: Docusaurus\\r\\n- **Deployment**: Docker + GitHub Actions\\r\\n\\r\\n## Development Timeline\\r\\n\\r\\n### Phase 1 (March - April 2026)\\r\\n- \u2705 Project setup and architecture\\r\\n- \u2705 User authentication module\\r\\n- \u2705 Employee CRUD operations\\r\\n- \u2705 API documentation\\r\\n\\r\\n### Phase 2 (May - June 2026)\\r\\n- Recruitment module\\r\\n- Advanced search and filters\\r\\n- Email notifications\\r\\n\\r\\n### Phase 3 (July - August 2026)\\r\\n- Analytics dashboard\\r\\n- Reporting system\\r\\n- Performance reviews\\r\\n\\r\\n## Get Involved\\r\\n\\r\\nWe\'re building in the open! Follow our progress:\\r\\n\\r\\n- **GitHub**: [LocalhostLegends/backend](https://github.com/LocalhostLegends/backend)\\r\\n- **Documentation**: [Check our docs](/docs/intro)\\r\\n- **Issues**: Report bugs or request features\\r\\n\\r\\n## Stay Connected\\r\\n\\r\\nThis blog will be updated regularly with:\\r\\n- Development updates\\r\\n- New feature announcements\\r\\n- Technical deep dives\\r\\n- Release notes\\r\\n\\r\\nLet\'s build something great together! \ud83d\ude80\\r\\n\\r\\n*\u2014 HR Platform Team*"}]}}')}}]);